const response = $.steps.scrapeYoutube.response || {};
const data = response.data || response;
const markdown = (data.markdown || data.content || data.text || '').slice(0, 10000);
const title = data.title || data.metadata?.title || '';
const description = data.metadata?.description || '';

return { markdown: markdown, title: title, description: description, url: $.input.youtubeUrl, analysisType: $.input.analysisType || 'all' };

const data = $.steps.extractVideoData.output;
const aType = data.analysisType;

let prompt = 'You are a video content analyst. Analyze the following YouTube video page content and provide comprehensive insights.

';
prompt += 'VIDEO TITLE: ' + data.title + '
';
prompt += 'URL: ' + data.url + '
';
prompt += 'DESCRIPTION: ' + data.description.slice(0, 500) + '

';
prompt += 'PAGE CONTENT:
' + data.markdown + '

';
prompt += 'ANALYSIS TYPE: ' + aType + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Provide a comprehensive summary of the video content
';
prompt += '- Extract key points and takeaways
';
prompt += '- Identify main topics discussed
';
prompt += '- Note any notable quotes or data points
';
prompt += '- Suggest potential clips or highlights for social sharing

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "title": "video title",
';
prompt += '  "summary": "3-5 sentence summary",
';
prompt += '  "keyPoints": ["point 1", "point 2"],
';
prompt += '  "topics": ["topic 1", "topic 2"],
';
prompt += '  "notableQuotes": ["quote 1"],
';
prompt += '  "highlights": [{ "topic": "", "description": "", "shareability": "high|medium|low" }],
';
prompt += '  "sentiment": "positive|neutral|negative",
';
prompt += '  "targetAudience": "who would benefit",
';
prompt += '  "socialSnippets": ["tweetable quote or insight"]
';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: $.steps.extractVideoData.output.title || '', summary: raw.slice(0, 500), keyPoints: [], topics: [], notableQuotes: [], highlights: [], sentiment: 'neutral', targetAudience: '', socialSnippets: [] }; }

const ai = $.steps.parseAI.output;
const rows = [];
rows.push([ai.title || '', $.input.youtubeUrl, ai.summary || '', (ai.keyPoints || []).join('; '), (ai.topics || []).join(', '), ai.sentiment || '', ai.targetAudience || '']);
return { rows: rows };

const ai = $.steps.parseAI.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'YouTube Video Analysis', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + (ai.title || 'Video') + '*\n<' + $.input.youtubeUrl + '|Watch Video>' } });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + (ai.summary || '').slice(0, 1500) } });

if (ai.keyPoints && ai.keyPoints.length > 0) {
  let kpText = '*Key Points:*\n';
  ai.keyPoints.slice(0, 6).forEach(function(kp, i) { kpText += (i + 1) + '. ' + kp + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: kpText.slice(0, 1800) } });
}

if (ai.socialSnippets && ai.socialSnippets.length > 0) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Social Snippets:*\n' + ai.socialSnippets.slice(0, 3).map(function(s) { return '> ' + s; }).join('\n') } });
}

blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Sentiment:*\n' + (ai.sentiment || 'N/A') },
  { type: 'mrkdwn', text: '*Audience:*\n' + (ai.targetAudience || 'N/A') }
] });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Saved to Google Sheets | Powered by Firecrawl + Claude AI' }] });
const fallbackText = 'Video Analysis: ' + (ai.title || $.input.youtubeUrl).slice(0, 80);
return { blocks, fallbackText };
